export function drawCard(type: CardType): Card {
  let deck: Card[];
  switch (type) {
    case 'event':
      deck = EVENT_CARDS;
      break;
    case 'item':
      deck = ITEM_CARDS;
      break;
    case 'omen':
      deck = OMEN_CARDS;
      break;
    default:
      deck = EVENT_CARDS;
  }
  return deck[Math.floor(Math.random() * deck.length)];
}
